namespace BgControls.Windows.Controls.DragDrop;internal abstract class DragDropProviderBase : IDisposable{    private IList<IScrollViewerAdapter> scrollViewersToAdjust;    private WeakReference lastNotApprovedDestination;    public bool IsDragging { get; internal set; }    public bool AutoBringIntoView { get; set; }    public double DragStartThreshold { get; set; }    public double ArrowVisibilityMinimumThreshold { get; set; }    public Point DragCueOffset { get; set; }    public DragDropOptions Options { get; set; }    internal virtual FrameworkElement LastApprovedDestination { get; set; }    internal List<IScrollViewerAdapter>? ScrollViewersToAdjust    {        get        {            if (scrollViewersToAdjust == null)            {                scrollViewersToAdjust = new List<IScrollViewerAdapter>();            }            return scrollViewersToAdjust;        }        set        {            scrollViewersToAdjust = value;        }    }    protected Point PreviousScrollAdjustPosition { get; set; }    protected DispatcherTimer ScrollViewerScrollTimer { get; set; }    public FrameworkElement? LastNotApprovedDestination    {        get        {            if (lastNotApprovedDestination == null)            {                return null;            }            return lastNotApprovedDestination.Target as FrameworkElement;        }        set        {            lastNotApprovedDestination = new WeakReference(value);        }    }    public event EventHandler<DragDropQueryEventArgs> DragQuery;    public event EventHandler<DragDropQueryEventArgs> DropQuery;    public event EventHandler<DragDropEventArgs> DragInfo;    public event EventHandler<DragDropEventArgs> DropInfo;    internal event EventHandler<DragArrowAdjustingEventArgs> DragArrowAdjusting;    internal static DragDropProviderBase Create(bool enableNativeDrag, DragExecutionMode mode)    {        if (mode == DragExecutionMode.Default)        {            return new DragDropProvider();        }        if (enableNativeDrag && RadControl.HasPermissions() && !BrowserInteropHelper.IsBrowserHosted)        {            return new DesktopDragDropProvider();        }        return new WPFSimulatedDragDropProvider();    }    public DragDropProviderBase()    {        Initialize();    }    public virtual void InitDefaultThresholds()    {        DragStartThreshold = 4.0;        ArrowVisibilityMinimumThreshold = 60.0;    }    internal virtual void Initialize()    {        if (!RadControl.IsInDesignMode)        {            AutoBringIntoView = true;            Options = GetDefaultOptions();            InitDefaultThresholds();            ScrollViewerScrollTimer = new DispatcherTimer            {                Interval = TimeSpan.FromSeconds(0.02)            };            ScrollViewerScrollTimer.Tick += OnScrollViewerScrollTimerCompleted;            ScrollViewersToAdjust = new List<IScrollViewerAdapter>();        }    }    public abstract void CancelDrag();    public abstract void StartDrag(FrameworkElement dragSource, object payload, object dragCue);    public abstract void SetAllowDrag(DependencyObject obj, bool value);    public abstract void SetAllowDrop(DependencyObject obj, bool value);    protected virtual void RaiseDragInfo()    {        if (Options.Source != null)        {            DragDropEventArgs e = new DragDropEventArgs(RadDragAndDropManager.DragInfoEvent, Options.Source, Options);            if (this.DragInfo != null)            {                this.DragInfo(this, e);            }        }    }    protected virtual DragDropQueryEventArgs RaiseDragQuery()    {        if (Options.Source != null)        {            var e = new DragDropQueryEventArgs(RadDragAndDropManager.DragQueryEvent, Options.Source, Options);            if (this.DragQuery != null)            {                this.DragQuery(this, e);                HandleAutoDrag(e);            }            return e;        }        return DragDropQueryEventArgs.EmptyArgs;    }    protected virtual void HandleAutoDrag(DragDropQueryEventArgs args)    {        if (!CanStartAutoDrag(args.QueryResult, args.Options.Source))        {            return;        }        args.QueryResult = true;        if (args.Options.DragCue == null)        {            Image image = FrameworkElementToImageConverter.ToImage(args.Options.Source);            image.Width = args.Options.Source.ActualWidth;            image.Height = args.Options.Source.ActualHeight;            args.Options.DragCue = image;        }        if (args.Options.Payload == null)        {            object obj = args.Options.Source.DataContext;            if (obj == null && args.Options.Source is ContentControl)            {                obj = ((ContentControl)args.Options.Source).Content;            }            args.Options.Payload = obj;        }    }    private static bool CanStartAutoDrag(bool? queryResult, FrameworkElement source)    {        bool flag = !queryResult.HasValue || (queryResult.HasValue && queryResult.Value);        bool result = source != null && source.GetValue(RadDragAndDropManager.AutoDragProperty) != null && (bool)source.GetValue(RadDragAndDropManager.AutoDragProperty);        if (flag)        {            return result;        }        return false;    }    protected virtual void RaiseDropInfo()    {        if (Options.Destination != null)        {            DragDropEventArgs e = new DragDropEventArgs(RadDragAndDropManager.DropInfoEvent, Options.Destination, Options);            if (this.DropInfo != null)            {                this.DropInfo(this, e);            }        }    }    protected virtual DragDropQueryEventArgs RaiseDropQuery()    {        if (Options.Destination != null)        {            LastNotApprovedDestination = null;            var e = new DragDropQueryEventArgs(RadDragAndDropManager.DropQueryEvent, Options.Source, Options);            if (this.DropQuery != null)            {                this.DropQuery(this, e);                HandleAutoDrag(e);            }            return e;        }        return DragDropQueryEventArgs.EmptyArgs;    }    protected virtual DragArrowAdjustingEventArgs RaiseDragArrowAdjusting(TransformGroup arrowTransformation)    {        DragArrowAdjustingEventArgs e = new DragArrowAdjustingEventArgs(RadDragAndDropManager.DragArrowAdjustingEvent, arrowTransformation);        if (this.DragArrowAdjusting != null)        {            this.DragArrowAdjusting(this, e);        }        return e;    }    internal virtual DragDropOptions GetDefaultOptions()    {        return new DragDropOptions();    }    private void OnScrollViewerScrollTimerCompleted(object sender, EventArgs e)    {        OnAdjustingScrollViewers();    }    internal virtual void OnAdjustingScrollViewers()    {        if (IsDragging && ArePointsNear(PreviousScrollAdjustPosition, Options.CurrentDragPoint, 5.0) && ScrollViewersToAdjust != null)        {            foreach (IScrollViewerAdapter item in ScrollViewersToAdjust)            {                AdjustScrollViewer(item, PreviousScrollAdjustPosition);            }            return;        }        ScrollViewerScrollTimer.Stop();        ScrollViewersToAdjust = null;    }    internal virtual void AdjustScrollViewer(IScrollViewerAdapter viewer, Point topLeftViewerPoint, Point currentPoint)    {        Point point = currentPoint;        Point point2 = new Point(point.X - topLeftViewerPoint.X, point.Y - topLeftViewerPoint.Y);        if (point2.Y > 0.0 && point2.Y < 40.0)        {            viewer.ScrollToVerticalOffset(viewer.VerticalOffset - 20.0 * ((40.0 - point2.Y) / 40.0));        }        if (point2.Y > viewer.ActualHeight - 40.0 && point2.Y < viewer.ActualHeight)        {            viewer.ScrollToVerticalOffset(viewer.VerticalOffset + 20.0 * ((40.0 - (viewer.ActualHeight - point2.Y)) / 40.0));        }        if (point2.X > 0.0 && point2.X < 40.0)        {            viewer.ScrollToHorizontalOffset(viewer.HorizontalOffset - 20.0 * ((40.0 - point2.X) / 40.0));        }        if (point2.X > viewer.ActualWidth - 40.0 && point2.X < viewer.ActualWidth)        {            viewer.ScrollToHorizontalOffset(viewer.HorizontalOffset + 20.0 * ((40.0 - (viewer.ActualWidth - point2.X)) / 40.0));        }    }    protected abstract void AdjustScrollViewer(IScrollViewerAdapter viewer, Point currentPoint);    internal bool ArePointsNear(Point currentPoint, Point otherPoint)    {        return ArePointsNear(currentPoint, otherPoint, DragStartThreshold);    }    protected static bool ArePointsNear(Point currentPoint, Point mouseClickPoint, double threshold)    {        if (Math.Abs(currentPoint.X - mouseClickPoint.X) < threshold)        {            return Math.Abs(currentPoint.Y - mouseClickPoint.Y) < threshold;        }        return false;    }    internal virtual Point GetRelativeDragCuePosition(Point relativeClickPoint, Point relativeDragPosition, FrameworkElement dragCueHost)    {        Point result = default(Point);        Point point = relativeClickPoint;        if (dragCueHost != null && dragCueHost.ActualHeight != 0.0 && dragCueHost.ActualWidth != 0.0)        {            if (relativeDragPosition.X < 0.0 || relativeDragPosition.X > dragCueHost.ActualWidth)            {                point.X = dragCueHost.ActualWidth / 2.0;            }            if (relativeDragPosition.Y < 0.0 || relativeDragPosition.Y > dragCueHost.ActualHeight)            {                point.Y = dragCueHost.ActualHeight / 2.0;            }            result.Y = point.Y - DragCueOffset.Y;            result.X = point.X - DragCueOffset.X;        }        return result;    }    protected virtual void NotifyPreviousApprovedDestination()    {        if (LastApprovedDestination != null)        {            Options.Status = DragStatus.DropImpossible;            FrameworkElement destination = Options.Destination;            DragStatus status = Options.Status;            Options.Destination = LastApprovedDestination;            RaiseDropInfo();            RaiseDragInfo();            Options.Destination = destination;            if (destination != null && destination != LastApprovedDestination)            {                Options.Status = status;                RaiseDropInfo();            }            LastApprovedDestination = null;        }    }    internal virtual void OnDropPossible()    {        if (Options.Destination != LastApprovedDestination && LastApprovedDestination != null)        {            NotifyPreviousApprovedDestination();        }        LastApprovedDestination = Options.Destination;    }    internal virtual void OnDropImpossible()    {        FrameworkElement destination = Options.Destination;        if (LastApprovedDestination != null)        {            NotifyPreviousApprovedDestination();        }        else        {            NotifySource();            NotifyNotApprovedDestination();        }        Options.Destination = destination;    }    protected virtual void NotifyNotApprovedDestination()    {        bool flag = false;        if (Options.Destination != null && LastNotApprovedDestination == null)        {            LastNotApprovedDestination = Options.Destination;            flag = true;        }        if (Options.Destination != LastNotApprovedDestination || flag)        {            DragStatus status = Options.Status;            FrameworkElement destination = Options.Destination;            Options.Destination = LastNotApprovedDestination;            Options.Status = DragStatus.DropImpossible;            RaiseDropInfo();            Options.Destination = destination;            LastNotApprovedDestination = Options.Destination;            Options.Status = status;        }    }    internal virtual void NotifySource()    {        DragStatus status = Options.Status;        Options.Status = DragStatus.DropImpossible;        RaiseDragInfo();        Options.Status = status;    }    internal virtual void Reset()    {        IsDragging = false;        DragCueOffset = default(Point);        if (Options.ParticipatingVisualRoots != null)        {            Options.ParticipatingVisualRoots.Clear();        }        Options = GetDefaultOptions();        if (ScrollViewersToAdjust != null)        {            ScrollViewersToAdjust.Clear();        }        LastApprovedDestination = null;        ResetCursor();    }    internal abstract void SetCursor();    internal abstract void ResetCursor();    public abstract void Dispose();}